class Solution:
    def minProcessingTime(self, processorTime: List[int], tasks: List[int]) -> int:
        processorTime.sort()
        tasks.sort(reverse=True)
        n = len(processorTime)
        res = 0
        for i in range(n):
            pt = processorTime[i]
            for j in range(4):
                res = max(res, pt + tasks[i * 4 + j])
        return res
